class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int total = 0, maxIncrease = 0, window = 0;
        for (int i = 0; i < customers.length; i++) {
            if (grumpy[i] == 0) total += customers[i];
            window += grumpy[i] == 1 ? customers[i] : 0;
            if (i >= minutes) window -= grumpy[i - minutes] == 1 ? customers[i - minutes] : 0;
            maxIncrease = Math.max(maxIncrease, window);
        }
        return total + maxIncrease;
    }
}
